mapper.select:
/* [SQL_ID:AuthorityUserMapper.selectAuthorityList]*/ SELECT ROW_NUMBER() OVER() AS RN , COUNT(1) OVER() AS TOTAL_COUNT , A.* FROM ( SELECT B.AUTHORITY_ID , B.AUTHORITY_NAME , B.AUTHORITY_TYPE , B.DESCRIPTION , B.CREATED_BY , TO_CHAR(B.CREATED_AT, 'YYYY-MM-DD HH24:MI') AS CREATED_AT , A.USER_ID FROM SYS_AUTHORITY_USER_MAP A INNER JOIN SYS_AUTHORITY B ON A.AUTHORITY_ID = B.AUTHORITY_ID
AND A.USER_ID = #{userId}
) A

/* [SQL_ID:AuthorityUserMapper.selectUserList]*/ SELECT ROW_NUMBER() OVER() AS RN , COUNT(1) OVER() AS TOTAL_COUNT , A.* FROM ( SELECT B.AUTHORITY_ID , B.AUTHORITY_NAME , B.AUTHORITY_TYPE , B.DESCRIPTION , B.CREATED_BY , TO_CHAR(B.CREATED_AT, 'YYYY-MM-DD HH24:MI') AS CREATED_AT , A.USER_ID FROM SYS_AUTHORITY_USER_MAP A INNER JOIN SYS_AUTHORITY B ON A.AUTHORITY_ID = B.AUTHORITY_ID
AND A.AUTHORITY_ID = #{authorityId}
) A

