mapper.select:
/* [SQL_ID:AuthorityUserMapper.existsAuthorization]*/ SELECT EXISTS ( SELECT 1 FROM SYS_USER A INNER JOIN SYS_AUTHORITY_USER_MAP B ON A.USER_ID = B.USER_ID INNER JOIN SYS_AUTHORITY_MENU_MAP C ON B.AUTHORITY_ID = C.AUTHORITY_ID INNER JOIN SYS_MENU D ON C.MENU_NO = D.MENU_NO
